48	const PROCESSING_FEE = 5;
49	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
50	
51	const BASE_PREMIUMS: Record<string, number> = {
52	  sword: 100,
53	  amulet: 60,
54	  staff: 80,
55	  potion: 40,
56	};
57	
58	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
59	
60	const sumBasePremiums = (items: Item[]): number =>
61	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
62	
63	const quotePremium = (items: Item[]): number => {
64	  const base = sumBasePremiums(items);
65	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
66	  return base + firstInsuranceSurcharge + PROCESSING_FEE;
67	};
68	
69	const runStep = (step: Step): StepResult => {
70	  if (step.op === "quote") {
71	    return { premium: quotePremium(step.items) };
72	  }
73	  return { payout: 0, remainingCap: 0 };
74	};
75	
76	export const runScenario = (scenario: Scenario): ScenarioResult => {
77	  return { results: scenario.steps.map(runStep) };
78	};
