const claimPayout = (_step: ClaimStep): StepResult => ({
  payout: 0,
  remainingCap: 0,
});

const runStep = (step: Step): StepResult =>
  step.op === "quote"
    ? { premium: quotePremium(step.items) }
    : claimPayout(step);
